// ── Harvest report engine (from xlsx tool) ────────────────────────────────────
const SKIP_PATTERNS = [
  /WEIGHT NEEDED/i,/NON-RADISH WEIGHT/i,/RADISH WEIGHT FOR BOOST/i,
  /^Approx\s/i,/^Total Sunflower/i,/^Total Pea/i,/^TOTAL\s/i,
  /^Gourmet Garnish/i,/^#REF/i,/^Check\s/i,
];
const MIX_SPLITS = {
  "Mellow Mix":   { Broccoli:0.45, "Purple Cabbage":0.45, Beets:0.10 },
  "Spicy Mix":    { Mustard:0.80,  "Purple Cabbage":0.20 },
  "Radish Blend": { Radish:1.00 },
  "Salad Boost":  { Radish:0.70, Arugula:0.09, Broccoli:0.21 },
  "Haute Blend":  null, "Brilliant Blend": null, "Violet Mosaic": null,
  "Peppercress (70%) & Beet (30%) blend": { Peppercress:0.70, Beets:0.30 },
};
function getMixFamily(n){ for(const p of Object.keys(MIX_SPLITS)) if(n.startsWith(p)) return p; return null; }
function getProductFamily(name){
  if(!name) return null;
  let n=name.trim();
  n=n.replace(/\s*(SPUD Label|SPUD 100g bag|1 lb bag|RETAIL)\s*/gi," ").replace(/\s*\((XS|S|M|L|XL)\)\s*$/,"").replace(/\s*\((XS|S|M|L|XL)\)\s*$/,"").trim();
  if(/^Baby Basil/i.test(n)||/^Mini Micro Basil/i.test(n)||/^Thai Basil/i.test(n)) return "Basil";
  if(/^Basil, Purple/i.test(n)) return "Purple Basil";
  if(/^Basil/i.test(n)) return "Basil";
  if(/^Baby Sky Hearts/i.test(n)) return "Sky Hearts";
  if(/^Cilantro, Short Stem/i.test(n)) return "Cilantro";
  if(/^Sunflower Shoots/i.test(n)) return "Sunflower Shoots";
  if(/^Shiso, Green/i.test(n)) return "Shiso (Green)";
  if(/^Shiso, Purple/i.test(n)) return "Shiso (Purple)";
  if(/^Shiso, Britton/i.test(n)) return "Shiso (Britton)";
  return n;
}
function getBaseCrop(name){
  const f=getProductFamily(name); if(!f) return null;
  if(/^(Red Radish|White Radish|Ruby Stem Radish)/.test(f)) return "Radish";
  return f;
}
function parseSheetDate(name){
  let s=name.trim().replace(/^(Mon|Tue|Wed|Thu|Fri|Sat|Sun)\s+/i,"").replace(/\bSPL\b\s*/i,"").trim();
  const M={Jan:1,Feb:2,Mar:3,Apr:4,May:5,Jun:6,Jul:7,Aug:8,Sep:9,Oct:10,Nov:11,Dec:12};
  const m=s.match(/^([A-Za-z]+)\s+(\d+)\s+(\d+)/);
  if(!m) return null;
  const mo=M[m[1]],d=parseInt(m[2]),y=2000+parseInt(m[3]);
  if(!mo||!d||!y) return null;
  return new Date(y,mo-1,d);
}
function shouldSkip(name,weightG){
  if(!name||typeof name!=="string") return true;
  if(SKIP_PATTERNS.some(p=>p.test(name.trim()))) return true;
  if(typeof weightG!=="number"||weightG<=0) return true;
  return false;
}
function parseXlsx(buffer){
  const wb=XLSX.read(buffer,{type:"array",cellFormula:false});
  const sheets=[];
  for(const sn of wb.SheetNames){
    const date=parseSheetDate(sn); if(!date) continue;
    const ws=wb.Sheets[sn];
    const raw=XLSX.utils.sheet_to_json(ws,{header:1,defval:null,raw:true});
    let ds=5;
    for(let i=0;i<Math.min(10,raw.length);i++) if(raw[i]&&String(raw[i][2]||"").includes("AI Calc")){ds=i+1;break;}
    const rows=[];
    for(let i=ds;i<raw.length;i++){
      const r=raw[i]; if(!r) continue;
      const nm=r[1],wg=r[2],u=r[3];
      if(shouldSkip(nm,wg)) continue;
      if(typeof u!=="number"||u<=0) continue;
      rows.push({name:String(nm).trim(),weightG:Number(wg),units:Number(u)});
    }
    if(rows.length>0) sheets.push({date,sheetName:sn,cropRows:rows});
  }
  return sheets;
}
function monthKey(d){return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}`;}
function weekMonday(d){const day=new Date(d),dow=day.getDay();day.setDate(day.getDate()+(dow===0?-6:1-dow));return day.toISOString().slice(0,10);}
function computeA(sheets,pkFn){
  const data={},periods=new Set();
  for(const{date,cropRows}of sheets){const pk=pkFn(date);periods.add(pk);for(const{name,weightG,units}of cropRows){const f=getProductFamily(name);if(!f)continue;const kg=(weightG*units)/1000;if(!data[f])data[f]={};data[f][pk]=(data[f][pk]||0)+kg;}}
  return{data,periods:[...periods].sort()};
}
function computeB(sheets,pkFn){
  const data={},periods=new Set(),unresolved=new Set();
  for(const{date,cropRows}of sheets){const pk=pkFn(date);periods.add(pk);for(const{name,weightG,units}of cropRows){const kg=(weightG*units)/1000,mix=getMixFamily(name);if(mix){const sp=MIX_SPLITS[mix];if(sp)for(const[c,p]of Object.entries(sp)){if(!data[c])data[c]={};data[c][pk]=(data[c][pk]||0)+kg*p;}else{const lb=mix+" (undivided)";unresolved.add(mix);if(!data[lb])data[lb]={};data[lb][pk]=(data[lb][pk]||0)+kg;}}else{const c=getBaseCrop(name);if(!c)continue;if(!data[c])data[c]={};data[c][pk]=(data[c][pk]||0)+kg;}}}
  return{data,periods:[...periods].sort(),unresolved:[...unresolved]};
}

